import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  ReactNode,
} from "react";
import { api, type User } from "@/lib/api";

interface AuthContextType {
  user: User | null;
  token: string | null;
  login: (email: string, password: string) => Promise<void>;
  logout: () => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);
AuthContext.displayName = "AuthContext";

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);

  // Rehydrate from localStorage on mount
  useEffect(() => {
    const storedToken = localStorage.getItem("prithvinet_token");
    const storedUser = localStorage.getItem("prithvinet_user");

    if (!storedToken || !storedUser) return;

    try {
      const parsedUser = JSON.parse(storedUser) as User;
      setToken(storedToken);
      setUser(parsedUser);
    } catch (error) {
      console.error("Failed to rehydrate auth state from localStorage:", error);
      localStorage.removeItem("prithvinet_token");
      localStorage.removeItem("prithvinet_user");
      setToken(null);
      setUser(null);
    }
  }, []);

  const login = async (email: string, password: string) => {
    const data = await api.auth.login(email, password);
    setToken(data.access_token);
    setUser(data.user);
    localStorage.setItem("prithvinet_token", data.access_token);
    localStorage.setItem("prithvinet_user", JSON.stringify(data.user));
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem("prithvinet_token");
    localStorage.removeItem("prithvinet_user");
  };

  return (
    <AuthContext.Provider
      value={{ user, token, login, logout, isAuthenticated: !!token }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
}

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Landmark, Wind, Droplets, Volume2, AlertTriangle, Factory, Globe } from "lucide-react";
import { Link } from "react-router-dom";

const tabs = [
  { id: "air", label: "Air Quality", icon: Wind, color: "sky" },
  { id: "water", label: "Water Quality", icon: Droplets, color: "blue" },
  { id: "alerts", label: "Active Alerts", icon: AlertTriangle, color: "red" },
  { id: "industries", label: "Industries", icon: Factory, color: "indigo" },
];

const aqiColor = (aqi: number | null) => {
  if (!aqi) return "bg-gray-100 text-gray-500";
  if (aqi < 50) return "bg-green-100 text-green-700";
  if (aqi < 100) return "bg-yellow-100 text-yellow-700";
  if (aqi < 150) return "bg-orange-100 text-orange-700";
  if (aqi < 200) return "bg-red-100 text-red-700";
  return "bg-purple-100 text-purple-700";
};

const aqiLabel = (aqi: number | null) => {
  if (!aqi) return "Unknown";
  if (aqi < 50) return "Good";
  if (aqi < 100) return "Moderate";
  if (aqi < 150) return "Unhealthy (Sensitive)";
  if (aqi < 200) return "Unhealthy";
  return "Very Unhealthy";
};

const sevColor: Record<string, string> = {
  critical: "bg-red-100 text-red-700",
  high: "bg-orange-100 text-orange-700",
  medium: "bg-yellow-100 text-yellow-700",
  low: "bg-blue-100 text-blue-700",
};
const indStatus: Record<string, string> = {
  active: "bg-blue-100 text-blue-700",
  compliant: "bg-green-100 text-green-700",
  violating: "bg-red-100 text-red-700",
  suspended: "bg-gray-100 text-gray-500",
};
interface Location {
  id: number;
  name: string;
  region: string;
}

interface AirReading {
  location: Location;
  aqi: number | null;
  pm25: number | null;
  pm10: number | null;
  recorded_at: string;
}

interface WaterReading {
  location: Location;
  ph: number | null;
  bod: number | null;
  dissolved_oxygen: number | null;
  recorded_at: string;
}

interface Alert {
  id: number;
  severity: "critical" | "high" | "medium" | "low";
  alert_type: string;
  message: string;
  created_at: string;
}

interface Industry {
  id: number;
  name: string;
  status: "active" | "compliant" | "violating" | "suspended";
  type: string;
  region: string;
  lat: number | null;
  lng: number | null;
}

