      if (t === "water" && !waterData) setWaterData((await api.public.waterQuality()) as any);
      if (t === "alerts" && !alertsData) setAlertsData((await api.public.alerts()) as any);
      if (t === "industries" && !industryData) setIndustryData((await api.public.industries()) as any);
